/**
 * SMS notification adapter — delivers notifications via SMS.
 *
 * Implements the NotificationAdapter interface so it can be registered
 * with the NotificationService. Provides:
 * - Message formatting: converts NotificationPayload to SMS-friendly text
 * - Phone number validation: validates E.164 format before sending
 * - Configurable transport: accepts an SmsTransport for actual delivery
 *   (defaults to an in-memory store for testing)
 *
 * Architecture: All notifications flow through EventBus → NotificationService
 * → this adapter. Do NOT call send() directly from services.
 */

import type {
  NotificationAdapter,
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Represents an SMS message ready for delivery.
 */
export interface SentSms {
  to: string;
  body: string;
  sentAt: Date;
}

/**
 * Transport interface for pluggable SMS delivery backends.
 * Implement this to integrate with Twilio, AWS SNS, etc.
 */
export interface SmsTransport {
  sendSms(sms: SentSms): Promise<{ success: boolean; error?: string }>;
}

/**
 * Configuration for the SMS adapter.
 */
export interface SmsAdapterConfig {
  /** Sender phone number or short code shown as the "From" number. */
  fromNumber: string;
  /** Application name used in message prefix. */
  appName: string;
  /** Optional custom transport. Defaults to in-memory store. */
  transport?: SmsTransport;
}

const DEFAULT_CONFIG: SmsAdapterConfig = {
  fromNumber: '+10000000000',
  appName: 'TaskFlow Pro',
};

/**
 * Validate that a string is a valid E.164 phone number.
 * E.164: starts with +, followed by 1-15 digits.
 */
export function isValidPhoneNumber(phone: string): boolean {
  return /^\+[1-9]\d{1,14}$/.test(phone);
}

/**
 * Normalize a phone number: trim whitespace and remove spaces/dashes.
 */
export function normalizePhoneNumber(phone: string): string {
  return phone.trim().replace(/[\s\-()]/g, '');
}

/**
 * Validate and normalize a recipient phone number.
 * Returns the normalized number or throws if invalid.
 */
export function validateRecipientPhone(recipient: string): string {
  const normalized = normalizePhoneNumber(recipient);
  if (!isValidPhoneNumber(normalized)) {
    throw new Error(`Invalid phone number: ${recipient}`);
  }
  return normalized;
}

/**
 * Format a NotificationPayload as a concise SMS message body.
 * SMS has a 160-character limit per segment, so keep it short.
 */
function formatSmsBody(payload: NotificationPayload, config: SmsAdapterConfig): string {
  return `[${config.appName}] ${payload.subject}: ${payload.body}`;
}

/**
 * In-memory SMS transport for testing and development.
 */
export class InMemorySmsTransport implements SmsTransport {
  private messages: SentSms[] = [];

  async sendSms(sms: SentSms): Promise<{ success: boolean; error?: string }> {
    this.messages.push(sms);
    return { success: true };
  }

  getSentMessages(): SentSms[] {
    return [...this.messages];
  }

  clear(): void {
    this.messages = [];
  }
}

export class SmsAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;

  private logger = new Logger('SmsAdapter');
  private config: SmsAdapterConfig;
  private transport: SmsTransport;
  private sentMessages: SentSms[] = [];

  constructor(config?: Partial<SmsAdapterConfig>) {
    this.config = { ...DEFAULT_CONFIG, ...config };
    this.transport = this.config.transport ?? new InMemorySmsTransport();
  }

  /**
   * Format a notification payload as an SMS message body.
   */
  formatMessage(payload: NotificationPayload): string {
    return formatSmsBody(payload, this.config);
  }

  /**
   * Validate and resolve the recipient phone number.
   * Returns the validated number or throws if invalid.
   */
  resolveRecipient(recipient: string): string {
    return validateRecipientPhone(recipient);
  }

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(`Sending SMS to ${payload.recipient}: ${payload.subject}`);

    // Validate recipient
    let resolvedRecipient: string;
    try {
      resolvedRecipient = this.resolveRecipient(payload.recipient);
    } catch (err) {
      const errorMsg = err instanceof Error ? err.message : 'Invalid recipient';
      this.logger.error(`Recipient validation failed: ${errorMsg}`);
      return {
        success: false,
        notification: payload,
        deliveredAt: new Date(),
        error: errorMsg,
      };
    }

    // Format message
    const body = this.formatMessage(payload);

    const sms: SentSms = {
      to: resolvedRecipient,
      body,
      sentAt: new Date(),
    };

    // Deliver via transport
    const transportResult = await this.transport.sendSms(sms);
    if (!transportResult.success) {
      this.logger.error(`Transport failed: ${transportResult.error}`);
      return {
        success: false,
        notification: payload,
        deliveredAt: new Date(),
        error: transportResult.error ?? 'SMS delivery failed',
      };
    }

    this.sentMessages.push(sms);

    return {
      success: true,
      notification: payload,
      deliveredAt: sms.sentAt,
    };
  }

  /**
   * Get all successfully sent SMS messages. Useful for testing.
   */
  getSentMessages(): SentSms[] {
    return [...this.sentMessages];
  }

  /**
   * Clear sent messages. Useful for testing.
   */
  clearSentMessages(): void {
    this.sentMessages = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import {
  SmsAdapter,
  InMemorySmsTransport,
  isValidPhoneNumber,
  normalizePhoneNumber,
  validateRecipientPhone,
  type SmsTransport,
  type SentSms,
} from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order-confirmation',
    channel: 'sms',
    recipient: '+15551234567',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    priority: 'normal',
    createdAt: new Date(),
    metadata: { orderId: 'order-1', userId: 'user-1' },
    ...overrides,
  };
}

describe('SmsAdapter', () => {
  let adapter: SmsAdapter;
  let transport: InMemorySmsTransport;

  beforeEach(() => {
    transport = new InMemorySmsTransport();
    adapter = new SmsAdapter({ transport });
  });

  describe('channel', () => {
    it('should report sms as its channel', () => {
      expect(adapter.channel).toBe('sms');
    });
  });

  describe('send', () => {
    it('should send an SMS successfully', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.notification).toBe(payload);
      expect(result.deliveredAt).toBeInstanceOf(Date);
      expect(result.error).toBeUndefined();
    });

    it('should store sent message with correct fields', async () => {
      const payload = makePayload();
      await adapter.send(payload);

      const messages = adapter.getSentMessages();
      expect(messages).toHaveLength(1);
      expect(messages[0]!.to).toBe('+15551234567');
      expect(messages[0]!.body).toContain('Order Confirmation');
      expect(messages[0]!.body).toContain('Widget x2');
    });

    it('should deliver via the transport', async () => {
      await adapter.send(makePayload());
      expect(transport.getSentMessages()).toHaveLength(1);
    });

    it('should normalize recipient phone number', async () => {
      const payload = makePayload({ recipient: '+1 (555) 123-4567' });
      await adapter.send(payload);

      const messages = adapter.getSentMessages();
      expect(messages[0]!.to).toBe('+15551234567');
    });

    it('should trim whitespace from recipient', async () => {
      const payload = makePayload({ recipient: '  +15551234567  ' });
      await adapter.send(payload);

      const messages = adapter.getSentMessages();
      expect(messages[0]!.to).toBe('+15551234567');
    });
  });

  describe('recipient validation', () => {
    it('should fail for empty recipient', async () => {
      const result = await adapter.send(makePayload({ recipient: '' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
    });

    it('should fail for recipient without +', async () => {
      const result = await adapter.send(makePayload({ recipient: '15551234567' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
    });

    it('should fail for recipient with letters', async () => {
      const result = await adapter.send(makePayload({ recipient: '+1555abc4567' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
    });

    it('should fail for too-short phone number', async () => {
      const result = await adapter.send(makePayload({ recipient: '+1' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
    });

    it('should not store message on validation failure', async () => {
      await adapter.send(makePayload({ recipient: 'bad' }));
      expect(adapter.getSentMessages()).toHaveLength(0);
    });
  });

  describe('message formatting', () => {
    it('should format message with app name prefix', () => {
      const payload = makePayload();
      const body = adapter.formatMessage(payload);

      expect(body).toContain('[TaskFlow Pro]');
      expect(body).toContain('Order Confirmation');
    });

    it('should use custom appName', () => {
      const customAdapter = new SmsAdapter({ appName: 'MyApp', transport });
      const payload = makePayload();
      const body = customAdapter.formatMessage(payload);

      expect(body).toContain('[MyApp]');
    });

    it('should include subject and body', () => {
      const payload = makePayload({
        subject: 'Test Subject',
        body: 'Test body content',
      });
      const body = adapter.formatMessage(payload);

      expect(body).toContain('Test Subject');
      expect(body).toContain('Test body content');
    });
  });

  describe('transport failure', () => {
    it('should return failure when transport rejects', async () => {
      const failingTransport: SmsTransport = {
        async sendSms(): Promise<{ success: boolean; error?: string }> {
          return { success: false, error: 'SMS gateway unavailable' };
        },
      };
      const failAdapter = new SmsAdapter({ transport: failingTransport });

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('SMS gateway unavailable');
    });

    it('should not store message on transport failure', async () => {
      const failingTransport: SmsTransport = {
        async sendSms(): Promise<{ success: boolean; error?: string }> {
          return { success: false, error: 'timeout' };
        },
      };
      const failAdapter = new SmsAdapter({ transport: failingTransport });

      await failAdapter.send(makePayload());
      expect(failAdapter.getSentMessages()).toHaveLength(0);
    });

    it('should use default error message when transport gives none', async () => {
      const failingTransport: SmsTransport = {
        async sendSms(): Promise<{ success: boolean; error?: string }> {
          return { success: false };
        },
      };
      const failAdapter = new SmsAdapter({ transport: failingTransport });

      const result = await failAdapter.send(makePayload());
      expect(result.error).toBe('SMS delivery failed');
    });
  });

  describe('getSentMessages / clearSentMessages', () => {
    it('should return empty array initially', () => {
      expect(adapter.getSentMessages()).toEqual([]);
    });

    it('should return copies (not mutable references)', async () => {
      await adapter.send(makePayload());
      const first = adapter.getSentMessages();
      const second = adapter.getSentMessages();
      expect(first).not.toBe(second);
      expect(first).toEqual(second);
    });

    it('should clear sent messages', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentMessages()).toHaveLength(1);

      adapter.clearSentMessages();
      expect(adapter.getSentMessages()).toHaveLength(0);
    });
  });

  describe('resolveRecipient', () => {
    it('should return normalized phone number', () => {
      expect(adapter.resolveRecipient('+1 (555) 123-4567')).toBe('+15551234567');
    });

    it('should throw for invalid phone number', () => {
      expect(() => adapter.resolveRecipient('nope')).toThrow('Invalid phone number');
    });
  });
});

describe('InMemorySmsTransport', () => {
  let transport: InMemorySmsTransport;

  beforeEach(() => {
    transport = new InMemorySmsTransport();
  });

  it('should store sent messages', async () => {
    const sms: SentSms = {
      to: '+15551234567',
      body: 'Hello',
      sentAt: new Date(),
    };
    const result = await transport.sendSms(sms);

    expect(result.success).toBe(true);
    expect(transport.getSentMessages()).toHaveLength(1);
    expect(transport.getSentMessages()[0]!.to).toBe('+15551234567');
  });

  it('should clear messages', async () => {
    await transport.sendSms({
      to: '+15551234567',
      body: 'test',
      sentAt: new Date(),
    });
    transport.clear();
    expect(transport.getSentMessages()).toHaveLength(0);
  });
});

describe('phone validation utilities', () => {
  describe('isValidPhoneNumber', () => {
    it('should accept valid E.164 numbers', () => {
      expect(isValidPhoneNumber('+15551234567')).toBe(true);
      expect(isValidPhoneNumber('+442071234567')).toBe(true);
      expect(isValidPhoneNumber('+86123456789')).toBe(true);
    });

    it('should reject numbers without +', () => {
      expect(isValidPhoneNumber('15551234567')).toBe(false);
    });

    it('should reject numbers starting with +0', () => {
      expect(isValidPhoneNumber('+05551234567')).toBe(false);
    });

    it('should reject empty string', () => {
      expect(isValidPhoneNumber('')).toBe(false);
    });
  });

  describe('normalizePhoneNumber', () => {
    it('should remove spaces, dashes, and parentheses', () => {
      expect(normalizePhoneNumber('+1 (555) 123-4567')).toBe('+15551234567');
    });

    it('should trim whitespace', () => {
      expect(normalizePhoneNumber('  +15551234567  ')).toBe('+15551234567');
    });
  });

  describe('validateRecipientPhone', () => {
    it('should return normalized number for valid input', () => {
      expect(validateRecipientPhone('+1 555-123-4567')).toBe('+15551234567');
    });

    it('should throw for invalid number', () => {
      expect(() => validateRecipientPhone('not-a-number')).toThrow('Invalid phone number');
    });
  });
});

